@page "/apply/personal-info"
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

@using sv_aa9f197e17aa47b1838be8f28f0af892.Models
@using sv_aa9f197e17aa47b1838be8f28f0af892.Services

<PageTitle>Personal Info – Step 1</PageTitle>
<h1>Step 1: Personal Information</h1>

<EditForm Model="AppState.PersonalInfo" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="AppState.PersonalInfo.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="AppState.PersonalInfo.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override async Task OnInitializedAsync()
    {
        await ProgressSource.NotifyChangedAsync(new WizardProgress
        {
            CurrentStep = 1,
            CompletedSteps = GetCompleted()
        });
    }

    private async Task Next()
    {
        var progress = new WizardProgress
        {
            CurrentStep = 2,
            CompletedSteps = GetCompleted()
        };
        progress.CompletedSteps.Add(1);
        await ProgressSource.NotifyChangedAsync(progress);
        Nav.NavigateTo("/apply/experience");
    }

    private HashSet<int> GetCompleted()
    {
        var set = new HashSet<int>();
        if (!string.IsNullOrWhiteSpace(AppState.PersonalInfo.Name)) set.Add(1);
        if (AppState.Experience.Any(e => !string.IsNullOrWhiteSpace(e.Company))) set.Add(2);
        if (AppState.References.Any(r => !string.IsNullOrWhiteSpace(r.Name))) set.Add(3);
        return set;
    }
}

