using sv_aa9f197e17aa47b1838be8f28f0af892.Components;
using sv_aa9f197e17aa47b1838be8f28f0af892.Models;
using sv_aa9f197e17aa47b1838be8f28f0af892.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

// Scoped = per-circuit = per-user on Blazor Server, so each applicant's data is isolated.
builder.Services.AddScoped<ApplicationState>();

// CascadingValueSource crosses render-mode boundaries, so the static layout
