    new CascadingValueSource<WizardProgress>(new WizardProgress(), isFixed: false));

﻿@inherits LayoutComponentBase
@using sv_aa9f197e17aa47b1838be8f28f0af892.Models

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (Progress is not null)
            {
                <nav class="d-flex gap-3 me-auto align-items-center">
                    @for (var i = 1; i <= Progress.TotalSteps; i++)
                    {
                        var step = i;
                        var label = step switch
                        {
                            1 => "Personal Info",
                            2 => "Experience",
                            3 => "References",
                            4 => "Review",
                            _ => $"Step {step}"
                        };
                        var href = step switch
                        {
                            1 => "/apply/personal-info",
                            2 => "/apply/experience",
                            3 => "/apply/references",
                            4 => "/apply/review",
                            _ => "#"
                        };
                        var active = step == Progress.CurrentStep;
                        var completed = Progress.CompletedSteps.Contains(step);
                        <a href="@href"
                           class="badge @(active ? "bg-primary" : completed ? "bg-success" : "bg-secondary")">
                            @step. @label
                        </a>
                    }
                    <span class="ms-2 text-muted">
                        Step @Progress.CurrentStep of @Progress.TotalSteps
                    </span>
                </nav>
            }
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    [CascadingParameter]
    private WizardProgress? Progress { get; set; }
}

